// =========================
// Local Types
// =========================

type DeliverableStatus =
  | "in_progress"
  | "in_review"
  | "approved"
  | "revision_requested";

// =========================
// Utility Functions
// =========================

function formatDate(dateStr: string) {
  return new Date(dateStr).toLocaleDateString("en-IN", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });
}

function formatDateTime(dateStr: string) {
  return new Date(dateStr).toLocaleDateString("en-IN", {
    day: "numeric",
    month: "short",
    year: "numeric",
    hour: "numeric",
    minute: "2-digit",
  });
}

function getPendingVersion(ver: DeliverableVersion) {
  if (ver.agencyApprovalStatus === "approved" && ver.clientApprovalStatus === "approved")
    return null;
  if (ver.agencyApprovalStatus === "approved") return "client";
  return "agency";
}

const STEPS = ["Draft", "Agency Review", "Client Review", "Current"];

function getStepIndex(ver: DeliverableVersion): number {
  if (ver.agencyApprovalStatus === "approved" && ver.clientApprovalStatus === "approved")
    return 3;
  if (ver.agencyApprovalStatus === "approved") return 2;
  return 1;
}

function getNextVersion(versions: DeliverableVersion[]): string {
  if (versions.length === 0) return "1.0";
  const sorted = [...versions].sort(
    (a, b) => parseFloat(b.version) - parseFloat(a.version)
  );
  const latest = parseFloat(sorted[0].version);
  return (Math.floor(latest) + 1).toString() + ".0";
}

function isVersionFullyApproved(ver: DeliverableVersion): boolean {
  return ver.agencyApprovalStatus === "approved" && ver.clientApprovalStatus === "approved";
}

// =========================
// Comment Node Component
// =========================

function CommentNode({
  comment,
  allComments,
  depth = 0,
  replyTo,
  setReplyTo,
  replyText,
  setReplyText,
  onSubmitReply,
}: {
  comment: CommentItem;
  allComments: CommentItem[];
  depth?: number;
  replyTo: string | null;
  setReplyTo: (id: string | null) => void;
  replyText: string;
  setReplyText: (text: string) => void;
  onSubmitReply: (parentId: string, content: string) => void;
}) {
  const children = allComments.filter((c) => c.parentId === comment.id);

  return (
    <div className={depth > 0 ? "ml-4" : ""}>
      <div className="rounded-md bg-muted/40 px-3 py-2 space-y-1">
        <div className="flex items-center gap-2">
          <span className="text-sm font-medium text-foreground">{comment.userName}</span>
          <span className="text-[10px] text-muted-foreground">{formatDateTime(comment.createdAt)}</span>
        </div>
        <p className="text-sm text-foreground/90">{comment.content}</p>
        <button
          onClick={() => {
            setReplyTo(replyTo === comment.id ? null : comment.id);
            setReplyText("");
          }}
          className="flex items-center gap-1 text-[11px] text-muted-foreground hover:text-foreground transition-colors"
        >
          <Reply className="size-3" />
          Reply
        </button>
      </div>

      {replyTo === comment.id && (
        <div className="ml-4 mt-2 space-y-2">
          <Textarea
            placeholder={`Reply to ${comment.userName}...`}
            value={replyText}
            onChange={(e) => setReplyText(e.target.value)}
            className="min-h-[60px] text-sm resize-none"
          />
          <div className="flex gap-2">
            <Button
              size="sm"
              disabled={!replyText.trim()}
              onClick={() => {
                onSubmitReply(comment.id, replyText.trim());
                setReplyTo(null);
                setReplyText("");
              }}
            >
              <Send className="size-3 mr-1" />
              Reply
            </Button>
            <Button size="sm" variant="ghost" onClick={() => { setReplyTo(null); setReplyText(""); }}>
              Cancel
            </Button>
          </div>
        </div>
      )}

      {children.length > 0 && (
        <div className="mt-2 space-y-2">
          {children.map((child) => (
            <CommentNode
              key={child.id}
              comment={child}
              allComments={allComments}
              depth={depth + 1}
              replyTo={replyTo}
              setReplyTo={setReplyTo}
              replyText={replyText}
              setReplyText={setReplyText}
              onSubmitReply={onSubmitReply}
            />
          ))}
        </div>
      )}
    </div>
  );
}

// =========================
// Version Comments Component
// =========================

function VersionComments({
  projectId,
  deliverableId,
  version,
}: {
  projectId: string;
  deliverableId: string;
  version: string;
}) {
  const [commentList, setCommentList] = useState<CommentItem[]>([]);
  const [showAddComment, setShowAddComment] = useState(false);
  const [commentInput, setCommentInput] = useState("");
  const [replyTo, setReplyTo] = useState<string | null>(null);
  const [replyText, setReplyText] = useState("");
  const [loading, setLoading] = useState(true);

  const fetchComments = useCallback(async () => {
    const result = await getDeliverableCommentsAction(projectId, deliverableId, version);
    if (result.success && result.comments) {
      setCommentList(result.comments);
    }
    setLoading(false);
  }, [projectId, deliverableId, version]);

  useEffect(() => {
    fetchComments();
  }, [fetchComments]);

  async function handlePostComment() {
    const trimmed = commentInput.trim();
    if (!trimmed) return;
    const result = await addDeliverableCommentAction(
      projectId,
      deliverableId,
      version,
      { content: trimmed }
    );
    if (result.success) {
      setCommentInput("");
      setShowAddComment(false);
      await fetchComments();
    }
  }

  async function handleReply(parentId: string, content: string) {
    const result = await addDeliverableCommentAction(
      projectId,
      deliverableId,
      version,
      { content, parentId }
    );
    if (result.success) {
      await fetchComments();
    }
  }

  const rootComments = commentList.filter((c) => !c.parentId);

  if (loading) {
    return (
      <div className="mt-3">
        <span className="text-xs text-muted-foreground">Loading comments...</span>
      </div>
    );
  }

  return (
    <div className="mt-3 space-y-2">
      {/* Comment count + add button */}
      <div className="flex items-center gap-2">
        {commentList.length > 0 && (
          <span className="text-xs text-muted-foreground tabular-nums">
            {commentList.length} {commentList.length === 1 ? "comment" : "comments"}
          </span>
        )}
        {!showAddComment && (
          <button
            onClick={() => setShowAddComment(true)}
            className="text-xs text-muted-foreground hover:text-foreground transition-colors"
          >
            Add a comment...
          </button>
        )}
      </div>

      {/* Inline add-comment textarea */}
      {showAddComment && (
        <div className="space-y-2">
          <Textarea
            value={commentInput}
            onChange={(e) => setCommentInput(e.target.value)}
            placeholder="Add a comment on this version..."
            rows={2}
            className="text-sm"
            autoFocus
          />
          <div className="flex gap-2">
            <Button size="sm" onClick={handlePostComment} disabled={!commentInput.trim()}>
              <Send className="size-3 mr-1" />
              Comment
            </Button>
            <Button
              size="sm"
              variant="ghost"
              onClick={() => { setShowAddComment(false); setCommentInput(""); }}
            >
              Cancel
            </Button>
          </div>
        </div>
      )}

      {/* Threaded comments */}
      {rootComments.length > 0 && (
        <div className="space-y-2">
          {rootComments.map((c) => (
            <CommentNode
              key={c.id}
              comment={c}
              allComments={commentList}
              replyTo={replyTo}
              setReplyTo={setReplyTo}
              replyText={replyText}
              setReplyText={setReplyText}
              onSubmitReply={handleReply}
            />
          ))}
        </div>
      )}
    </div>
  );
}

