export function DeliverableDetailPage() {
  const params = useParams();
  const router = useRouter();
  const { user, isLoading } = useAuth();
  const [showUploadForm, setShowUploadForm] = useState(false);
  const [uploadVersion, setUploadVersion] = useState("");
  const [uploadNote, setUploadNote] = useState("");
  const [uploadFileUrl, setUploadFileUrl] = useState("");
  const [deliverable, setDeliverable] = useState<DeliverableDetail | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const projectId = params.id as string;
  const deliverableId = params.deliverableId as string;

  const fetchDeliverable = useCallback(async () => {
    const result = await getDeliverableDetailAction(projectId, deliverableId);
    if (result.success && result.deliverable) {
      setDeliverable(result.deliverable);
      setError(null);
    } else {
      setError(result.error || "Failed to load deliverable");
    }
    setLoading(false);
  }, [projectId, deliverableId]);

  useEffect(() => {
    if (!isLoading && !user) {
      router.push("/auth/signin");
    }
  }, [user, isLoading, router]);

  useEffect(() => {
    if (user) {
      fetchDeliverable();
    }
  }, [user, fetchDeliverable]);

  useEffect(() => {
    if (deliverable) {
      document.title = `${deliverable.title} — ${deliverable.milestoneTitle} | Project Manager`;
    }
  }, [deliverable]);

  if (isLoading || !user) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <p className="text-muted-foreground">Loading...</p>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <p className="text-muted-foreground">Loading deliverable...</p>
      </div>
    );
  }

  if (error || !deliverable) {
    return (
      <div className="flex flex-1 flex-col items-center justify-center gap-4">
        <p className="text-muted-foreground">{error || "Deliverable not found."}</p>
        <Button asChild variant="outline">
          <Link href={`/projects/${projectId}`}>
            <ArrowLeft className="mr-2 h-4 w-4" />
            Back to Project
          </Link>
        </Button>
      </div>
    );
  }

  const sortedVersions = [...deliverable.versions].sort(
    (a, b) => parseFloat(b.version) - parseFloat(a.version)
  );
  const latestVersion = sortedVersions[0];
  const pendingStep = latestVersion ? getPendingVersion(latestVersion) : null;
  const suggestedVersion = getNextVersion(deliverable.versions);

  const isAgencySide =
    user.role === "agency_owner" ||
    user.role === "project_manager" ||
    user.role === "team_member";
  const canUpload = user.id === deliverable.assignedTo || isAgencySide;
  const isAgencyApprover = user.role === "agency_owner" || user.role === "project_manager";
  const isClientApprover = user.role === "client";

  const handleUploadVersion = async () => {
    if (!uploadNote.trim() || !uploadVersion.trim()) return;
    const result = await uploadDeliverableVersionAction(projectId, deliverableId, {
      version: uploadVersion.trim(),
      note: uploadNote,
      fileUrl: uploadFileUrl || "/files/untitled",
    });
    if (result.success) {
      setUploadVersion("");
      setUploadNote("");
      setUploadFileUrl("");
      setShowUploadForm(false);
      await fetchDeliverable();
    }
  };

  const handleApproveAgency = async (version: string) => {
    const result = await approveAgencyAction(projectId, deliverableId, version);
    if (result.success) {
      await fetchDeliverable();
    }
  };

  const handleApproveClient = async (version: string) => {
    const result = await approveClientAction(projectId, deliverableId, version);
    if (result.success) {
      await fetchDeliverable();
    }
  };

  const showAgencyApprove =
    pendingStep === "agency" && isAgencyApprover;
  const showClientApprove =
    pendingStep === "client" && isClientApprover;

  return (
    <div className="flex flex-col gap-6 p-6">
      {/* Back link + Header */}
      <div className="flex flex-col gap-4">
        <Button asChild variant="ghost" size="sm" className="w-fit -ml-2">
          <Link href={`/projects/${projectId}`}>
            <ArrowLeft className="mr-2 h-4 w-4" />
            Back to Project
          </Link>
        </Button>

        <div className="flex flex-wrap items-start justify-between gap-4">
          <div className="space-y-2">
            <div className="flex items-center gap-2 flex-wrap">
              <h1 className="text-2xl font-semibold">{deliverable.title}</h1>
              <Badge
                variant="secondary"
                className={`text-[10px] ${deliverableStatusColors[deliverable.status as DeliverableStatus] || ""}`}
              >
                {formatLabel(deliverable.status)}
              </Badge>
              {deliverable.currentVersion !== "0" && (
                <Badge variant="outline" className="text-[10px] font-mono">
                  v{deliverable.currentVersion} (current)
                </Badge>
              )}
            </div>
            <p className="text-sm text-muted-foreground max-w-2xl">
              {deliverable.description}
            </p>
          </div>
        </div>
      </div>

      {/* Info row */}
      <div className="flex flex-wrap items-center gap-2 text-sm text-muted-foreground">
        <span className="flex items-center gap-1">
          <User className="size-3.5" />
          <span className="font-medium text-foreground">
            {deliverable.assignedToName}
          </span>
        </span>
        <span className="text-muted-foreground/40">|</span>
        <span>
          Milestone:{" "}
          <Link
            href={`/projects/${projectId}#milestones`}
            className="font-medium text-foreground hover:underline"
          >
            {deliverable.milestoneTitle}
          </Link>
        </span>
        <span className="text-muted-foreground/40">|</span>
        <span>
          Task:{" "}
          <Link
            href={`/projects/${projectId}#tasks`}
            className="font-medium text-foreground hover:underline"
          >
            {deliverable.taskTitle}
          </Link>
        </span>
      </div>

      {/* Approval section — only when latest version needs approval */}
      {latestVersion && pendingStep && (
        <div className="rounded-lg border bg-card p-4 space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium">
                v{latestVersion.version} awaiting approval
              </p>
              <p className="text-xs text-muted-foreground mt-0.5">
                {latestVersion.note}
              </p>
            </div>
          </div>

          {/* Step indicator */}
          <div className="flex items-center gap-1">
            {STEPS.map((step, i) => {
              const active = getStepIndex(latestVersion);
              const done = i < active;
              const current = i === active;
              return (
                <div key={step} className="flex items-center gap-1">
                  <div className="flex items-center gap-1.5">
                    {done ? (
                      <CheckCircle2 className="size-4 text-primary" />
                    ) : current ? (
                      <Circle className="size-4 text-primary fill-primary/20" />
                    ) : (
                      <Circle className="size-4 text-muted-foreground/30" />
                    )}
                    <span
                      className={`text-xs ${
                        done || current
                          ? "font-medium text-foreground"
                          : "text-muted-foreground/50"
                      }`}
                    >
                      {step}
                    </span>
                  </div>
                  {i < STEPS.length - 1 && (
                    <div
                      className={`mx-1 h-px w-6 ${
                        done ? "bg-primary" : "bg-muted-foreground/20"
                      }`}
                    />
                  )}
                </div>
              );
            })}
          </div>

          {/* Who approved already */}
          <div className="flex flex-wrap gap-4 text-xs text-muted-foreground">
            {latestVersion.agencyApprovalStatus === "approved" && (
              <span>
                Agency: {latestVersion.agencyApprovedByName || "Approved"}{" "}
                &middot; {latestVersion.agencyApprovedAt && formatDateTime(latestVersion.agencyApprovedAt)}
              </span>
            )}
            {latestVersion.clientApprovalStatus === "approved" && (
              <span>
                Client: {latestVersion.clientApprovedByName || "Approved"}{" "}
                &middot; {latestVersion.clientApprovedAt && formatDateTime(latestVersion.clientApprovedAt)}
              </span>
            )}
          </div>

          {/* Single approve button */}
          {(showAgencyApprove || showClientApprove) && (
            <Button
              size="sm"
              onClick={() =>
                showAgencyApprove
                  ? handleApproveAgency(latestVersion.version)
                  : handleApproveClient(latestVersion.version)
              }
            >
              {showAgencyApprove ? "Approve (Agency)" : "Approve (Client)"}
            </Button>
          )}
        </div>
      )}

      {/* Version list */}
      <div className="space-y-3">
        <h2 className="text-lg font-semibold">
          Versions ({deliverable.versions.length})
        </h2>

        <div className="space-y-2">
          {sortedVersions.map((ver) => {
            const isCurrent = ver.version === deliverable.currentVersion;
            const isSuperseded =
              !isCurrent && isVersionFullyApproved(ver);
            const isDraft = !isCurrent && !isVersionFullyApproved(ver);
            return (
              <div
                key={ver.version}
                className={`rounded-lg border p-3 transition-colors ${
                  isCurrent ? "border-primary/30 bg-primary/5" : ""
                }`}
              >
                <div className="flex items-center gap-3">
                  <Badge
                    variant={isCurrent ? "default" : "outline"}
                    className="shrink-0 text-[10px] font-mono"
                  >
                    v{ver.version}
                  </Badge>

                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2 flex-wrap">
                      <p className="text-sm truncate">{ver.note}</p>
                      {isCurrent && (
                        <Badge
                          variant="secondary"
                          className="shrink-0 text-[10px]"
                        >
                          Current
                        </Badge>
                      )}
                      {isSuperseded && (
                        <Badge
                          variant="outline"
                          className="shrink-0 text-[10px] text-muted-foreground"
                        >
                          Superseded
                        </Badge>
                      )}
                      {isDraft && (
                        <Badge
                          variant="secondary"
                          className="shrink-0 text-[10px] bg-status-draft text-status-draft-foreground"
                        >
                          Draft
                        </Badge>
                      )}
                    </div>
                    <p className="text-xs text-muted-foreground mt-0.5">
                      {ver.uploadedByName} &middot; {formatDate(ver.uploadedAt)}
                    </p>
                  </div>

                  {ver.fileUrl && (
                    <a
                      href={ver.fileUrl}
                      download
                      className="shrink-0 inline-flex items-center gap-1 rounded-md px-2 py-1 text-[11px] font-medium text-primary hover:bg-primary/10 transition-colors"
                    >
                      <Download className="size-3" />
                      {ver.fileUrl.split(".").pop()?.toUpperCase() ?? "FILE"}
                    </a>
                  )}
                </div>

                <VersionComments
                  projectId={projectId}
                  deliverableId={deliverableId}
                  version={ver.version}
                />
              </div>
            );
          })}
        </div>
      </div>

      {/* Upload form (assignee only) */}
      {canUpload && (
        <div className="space-y-3">
          {!showUploadForm ? (
            <Button size="sm" onClick={() => setShowUploadForm(true)}>
              <Upload className="mr-2 h-4 w-4" />
              Upload New Version
            </Button>
          ) : (
            <div className="rounded-lg border bg-card p-4 space-y-3">
              <p className="text-sm font-medium">New Version</p>
              <div>
                <label className="text-xs font-medium text-muted-foreground">
                  Version Number
                </label>
                <Input
                  value={uploadVersion}
                  onChange={(e) => setUploadVersion(e.target.value)}
                  placeholder={suggestedVersion}
                  className="mt-1 w-32 font-mono"
                />
              </div>
              <div>
                <label className="text-xs font-medium text-muted-foreground">
                  Version Note
                </label>
                <Textarea
                  value={uploadNote}
                  onChange={(e) => setUploadNote(e.target.value)}
                  placeholder="Describe what changed in this version"
                  className="mt-1"
                  rows={2}
                />
              </div>
              <div>
                <label className="text-xs font-medium text-muted-foreground">
                  File URL
                </label>
                <Input
                  value={uploadFileUrl}
                  onChange={(e) => setUploadFileUrl(e.target.value)}
                  placeholder="/files/deliverable-v2.fig"
                  className="mt-1"
                />
              </div>
              <div className="flex gap-2">
                <Button size="sm" onClick={handleUploadVersion}>
                  Upload
                </Button>
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => {
                    setShowUploadForm(false);
                    setUploadVersion("");
                    setUploadNote("");
                    setUploadFileUrl("");
                  }}
                >
                  Cancel
                </Button>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

